vtest('splits into uniform pairs', 'Six items, size two.', () => {
  expect(chunk([1, 2, 3, 4, 5, 6], 2)).toEqual([
    [1, 2],
    [3, 4],
    [5, 6],
  ]);
});

vtest(
  'splits into uniform triples',
  'Same input, different chunk size.',
  () => {
    expect(chunk([1, 2, 3, 4, 5, 6], 3)).toEqual([
      [1, 2, 3],
      [4, 5, 6],
    ]);
  },
);

vtest(
  'final chunk shorter than size',
  'Five items, size two — final chunk has one element.',
  () => {
    expect(chunk([1, 2, 3, 4, 5], 2)).toEqual([[1, 2], [3, 4], [5]]);
  },
);

vtest(
  'no item loss',
  'Property: the flattened chunks equal the original array.',
  () => {
    const xs = [10, 20, 30, 40, 50, 60, 70];
    for (const n of [1, 2, 3, 4, 5, 6, 7]) {
      expect(chunk(xs, n).flat()).toEqual(xs);
    }
  },
);

vtest('empty input → empty output', 'No work to do.', () => {
  expect(chunk([], 3)).toEqual([]);
});

vtest(
  'size larger than length',
  'Returns a single chunk containing the whole array.',
  () => {
    expect(chunk([1, 2, 3], 10)).toEqual([[1, 2, 3]]);
  },
);

vtest('size <= 0 throws', '`size` is a positive integer.', () => {
  expect(() => chunk([1, 2, 3], 0)).toThrow(RangeError);
  expect(() => chunk([1, 2, 3], -1)).toThrow(RangeError);
});

vtest('removes duplicates in order of first occurrence', 'Order-preserving.', () => {
  expect(unique([1, 2, 1, 3, 2, 4])).toEqual([1, 2, 3, 4]);
});

vtest(
  'is case-sensitive for strings',
  '`"a"` and `"A"` are distinct under the default comparator.',
  () => {
    expect(unique(['a', 'A', 'a', 'B'])).toEqual(['a', 'A', 'B']);
  },
);

vtest('handles an empty input', 'Edge case.', () => {
  expect(unique<number>([])).toEqual([]);
});

vtest(
  'collapses objects by id',
  'The canonical use case — merging two paginated result pages.',
  () => {
    const rows = [
      { id: 1, name: 'a' },
      { id: 2, name: 'b' },
      { id: 1, name: 'a-updated' },
    ];
    expect(unique(rows, (r) => r.id)).toEqual([
      { id: 1, name: 'a' },
      { id: 2, name: 'b' },
    ]);
  },
);

vtest(
  'allows case-insensitive string dedup',
  'Lowercasing the key folds `"a"` and `"A"` into the same bucket.',
  () => {
    expect(unique(['a', 'A', 'b'], (s) => s.toLowerCase())).toEqual([
      'a',
      'b',
    ]);
  },
);

vtest('single digit', 'The simplest possible input.', () => {
  expect(tokenize('7')).toEqual([{ kind: 'NUMBER', value: 7 }]);
});

vtest('multiple digits become one token', 'The scanner is greedy.', () => {
  expect(tokenize('1234')).toEqual([{ kind: 'NUMBER', value: 1234 }]);
});

vtest(
  'plus and minus',
  'Tests that adjacent operator characters tokenize independently — `1+-2` produces three tokens, not one.',
  () => {
    // Whitespace is optional and ignored.
    const tokens = tokenize('1+-2');
    expect(tokens).toEqual([
      { kind: 'NUMBER', value: 1 },
      { kind: 'OP', op: '+' },
      { kind: 'OP', op: '-' },
      { kind: 'NUMBER', value: 2 },
    ]);
  },
);

vtest(
  'parens around an expression',
  'Snippet-extractor stress: this body uses a template literal with `${}` interpolation that contains a `(` and a `)` — the scanner must not treat those as the outer call boundary.',
  () => {
    const input = `(1 + 2)`;
    const expected = `(1 + 2)`;
    // The literal we just built (`${expected}`) and the input should agree.
    expect(input).toBe(expected);
    expect(tokenize(input)).toEqual([
      { kind: 'LPAREN' },
      { kind: 'NUMBER', value: 1 },
      { kind: 'OP', op: '+' },
      { kind: 'NUMBER', value: 2 },
      { kind: 'RPAREN' },
    ]);
  },
);

vtest(
  'skips spaces, tabs, and newlines',
  'A body spanning multiple lines with mixed whitespace.',
  () => {
    // The tokenizer should treat all of these as equivalent.
    const a = tokenize('1 + 2');
    const b = tokenize('1\t+\t2');
    const c = tokenize('1\n+\n2');
    expect(a).toEqual(b);
    expect(b).toEqual(c);
  },
);

vtest(
  'string args containing parens do not confuse anything',
  'Snippet-extractor stress: the string literal `")"` below contains a paren that must NOT close the outer `vtest(` call.',
  () => {
    const paren = ')';
    const fakeOpen = '(';
    expect(paren).toBe(')');
    expect(fakeOpen).toBe('(');
    // Sanity: tokenizer still works on a real expression with parens.
    expect(tokenize('(7)')).toEqual([
      { kind: 'LPAREN' },
      { kind: 'NUMBER', value: 7 },
      { kind: 'RPAREN' },
    ]);
  },
);

vtest(
  'throws on an unknown character',
  'The error message mentions the offending character and its zero-based offset.',
  () => {
    expect(() => tokenize('1 ? 2')).toThrow(
      /unexpected character \? at offset 2/,
    );
  },
);

vtest(
  'nested arrow function in the body',
  'Snippet-extractor stress: defining and invoking an inner arrow function with its own parens.',
  () => {
    const double = (n: number): number => n * 2;
    const values = [1, 2, 3].map(double);
    expect(values).toEqual([2, 4, 6]);
  },
);

vtest('identity for interior values', 'No-op when the value is interior.', () => {
  expect(clamp(5, 0, 10)).toBe(5);
});

vtest(
  'identity at the endpoints',
  'Both endpoints are inclusive — clamping at the boundary is a no-op.',
  () => {
    expect(clamp(0, 0, 10)).toBe(0);
    expect(clamp(10, 0, 10)).toBe(10);
  },
);

vtest('clamps below `lo`', 'Negative example.', () => {
  expect(clamp(-3, 0, 10)).toBe(0);
});

vtest('clamps above `hi`', 'Above-bound example.', () => {
  expect(clamp(42, 0, 10)).toBe(10);
});

vtest(
  'NaN propagates',
  '`Math.min(NaN, ...)` is `NaN`, so the result is `NaN` for any clamp range.',
  () => {
    expect(clamp(Number.NaN, 0, 1)).toBeNaN();
  },
);

vtest(
  'Infinity is clamped',
  '`+Infinity` becomes `hi`; `-Infinity` becomes `lo`.',
  () => {
    expect(clamp(Number.POSITIVE_INFINITY, 0, 1)).toBe(1);
    expect(clamp(Number.NEGATIVE_INFINITY, 0, 1)).toBe(0);
  },
);

vtest('exact endpoint identity at t=0 and t=1', 'Required by the monotonic form.', () => {
  expect(lerp(10, 20, 0)).toBe(10);
  expect(lerp(10, 20, 1)).toBe(20);
});

vtest('returns the midpoint at t=0.5', 'The simplest non-trivial case.', () => {
  expect(lerp(0, 100, 0.5)).toBe(50);
});

vtest(
  'extrapolates when t is outside [0,1]',
  '`lerp` does not clamp — `t = 1.5` returns the point a further half-step past `b`.',
  () => {
    expect(lerp(0, 100, 1.5)).toBe(150);
    expect(lerp(0, 100, -0.5)).toBe(-50);
  },
);

vtest('round-trips lerp at a few sample points', '`inverseLerp ∘ lerp` is the identity on `t`.', () => {
  for (const t of [0, 0.25, 0.5, 0.75, 1]) {
    expect(inverseLerp(10, 20, lerp(10, 20, t))).toBeCloseTo(t);
  }
});

vtest(
  'returns 0 / 1 at the endpoints',
  'Sanity boundary check.',
  () => {
    expect(inverseLerp(10, 20, 10)).toBe(0);
    expect(inverseLerp(10, 20, 20)).toBe(1);
  },
);

vtest(
  'joins space-separated words',
  'A plain English phrase becomes a single identifier.',
  () => {
    expect(camel('hello world')).toBe('helloWorld');
  },
);

vtest(
  'lowercases an already-camel input',
  'Round-tripping `camelCase → camel` is the identity, modulo first-letter casing.',
  () => {
    expect(camel('helloWorld')).toBe('helloWorld');
  },
);

vtest(
  'joins hyphen-separated and snake-separated forms',
  'Mixed separators are all treated equivalently.',
  () => {
    expect(camel('hello-world')).toBe('helloWorld');
    expect(camel('hello_world')).toBe('helloWorld');
  },
);

vtest(
  'title-cases the first token',
  'Distinguishes `pascal` from `camel`.',
  () => {
    expect(pascal('hello world')).toBe('HelloWorld');
  },
);

vtest('handles a single token', 'Trivial case.', () => {
  expect(pascal('hello')).toBe('Hello');
});

vtest('splits camelCase by case boundary', 'The core tokenizer behaviour.', () => {
  expect(kebab('helloWorld')).toBe('hello-world');
  expect(snake('helloWorld')).toBe('hello_world');
});

vtest(
  'collapses repeated separators',
  'Multiple non-alphanumerics in a row produce a single boundary, not multiple empty tokens.',
  () => {
    expect(kebab('hello   world')).toBe('hello-world');
    expect(snake('hello___world')).toBe('hello_world');
  },
);

vtest(
  'keeps acronyms intact in camel output',
  'For `HTTPServer`, the boundary lands between `HTTP` and `Server` — not inside `HTTP`.',
  () => {
    expect(camel('HTTPServer')).toBe('httpServer');
    expect(kebab('HTTPServer')).toBe('http-server');
  },
);

vtest(
  'handles trailing acronyms',
  'A trailing all-caps run becomes its own final token.',
  () => {
    expect(kebab('parseURL')).toBe('parse-url');
    expect(snake('toJSON')).toBe('to_json');
  },
);

vtest('lowercases ASCII', 'Trivial casefolding.', () => {
  expect(slugify('Hello World')).toBe('hello-world');
});

vtest(
  'strips diacritics via NFD',
  'Combining marks are removed; the underlying base letter survives.',
  () => {
    expect(slugify('Héllo Wörld')).toBe('hello-world');
    expect(slugify('Café crème')).toBe('cafe-creme');
  },
);

vtest(
  'drops punctuation',
  'Any non-alphanumeric character becomes a separator candidate.',
  () => {
    expect(slugify("It's a test!")).toBe('it-s-a-test');
  },
);

vtest(
  'collapses runs of separators',
  'Multiple symbols in a row collapse to a single hyphen.',
  () => {
    expect(slugify('a   b---c')).toBe('a-b-c');
  },
);

vtest(
  'trims leading and trailing hyphens',
  'After collapsing, the result is stripped on both ends.',
  () => {
    expect(slugify('  --leading--  ')).toBe('leading');
    expect(slugify('!!middle!!')).toBe('middle');
  },
);

vtest(
  'returns empty for separator-only input',
  'No alphanumerics means no slug.',
  () => {
    expect(slugify('!!!')).toBe('');
    expect(slugify('   ')).toBe('');
  },
);

vtest(
  'preserves digits',
  'Numbers are alphanumerics — they survive the filter.',
  () => {
    expect(slugify('2026 roadmap')).toBe('2026-roadmap');
  },
);
